import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"种族类别","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/种族类别.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/种族类别.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/种族类别.md"};function o(d,b,l,_,i,A){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"种族类别",tabindex:"-1"},[t("种族类别 "),r("a",{class:"header-anchor",href:"#种族类别","aria-label":'Permalink to "种族类别"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),n('<h1 id="种族类别-1" tabindex="-1">种族类别 <a class="header-anchor" href="#种族类别-1" aria-label="Permalink to &quot;种族类别&quot;">​</a></h1><p>FATE能力组（种族类别）<br> 描述：出自型月系列世界观，本能力组为该世界观内从者与非从者具有的特殊种族类别，在购买后主神会将其赋予给轮回者，使轮回者获得近似的能力。<br> 若无特殊说明，购买种族类别会占据血统位，如同购买了一次性血统一样计算。<br> 若无特殊说明，因种族类别获得的技能不会提供自由属性。</p><p>从者<br> 价格：B+2400<br> 描述：从者是 TYPE-MOON 世界观中的魔术现象，从者是死后，升格为超越人的存在的英雄之魂被称为“英灵”。他们通过仪式被召唤到现世，成为可以被使役的存在，即为“从者（Servant）”。<br> 通常情况下人类召唤出的英灵只是英灵本体的分身，不存在人格，完成任务后便会消失返回英灵之座。但主神提供的版本是直接改变了你作为生物的存在模式，因此与原作版本的能力并不一致。<br> 效果：<br> 从者可以灵体/实体化，这需要一个移动动作切换，切换到灵体化的状态下可以维持一场景。<br> 灵体状态下将获得灵体生物特性，实体状态下具备正常肉体而没有灵体生物的性质。</p><p>由于从者的肉体本质为魔力构成，只要有充足的魔力供给就无需进食、睡眠，但实体化状态下的从者如同常规的人形生物一般会被致盲、窒息、反胃……从者在死亡时不会留下遗骸而是飘散为基本的魔力粒子，灵魂则返回英灵殿（轮回者会正常死亡）。从者具有黑暗视觉，可以感受到魔力波动等神秘侧气息，这是一种新建非线性感知类能力。</p><p>若你在购买本兑换后不具有魔力能量池，则开启魔力能量池，分类为生命魔力，恢复方式为：你进行了完整的长休息后，回复所有魔力。<br> 进行一次短休息后，就恢复等同于耐力属性点魔力（最高为上限的四分之一）。<br> 每日恢复的魔力不能超过上限的三倍。</p><p>从者是神秘侧最顶级的存在，具有【神秘A】，神秘仅会在型月世界观（且ST允许的情况）下生效。<br> 具有【神秘】的生物在受到不具有【神秘】的攻击时，最终承受的伤害根据【神秘】等级将减少20%/40%/60%/80%/100%（D，C，B，A，EX）的数值。</p><p>传奇造魔<br> 价格：B+2400<br> 描述：传奇造魔是非天然的强大生命（如高等级的人偶、机器人和人造生命体），它们或许没有生命和灵魂，但这不影响它们的正常活动。<br> 效果：<br> 传奇造魔免疫心灵来源的效果，也对创伤，疾病，毒素来源的效果免疫，这些免疫等级统一视为B级。但如果传奇造魔具有心智或者灵魂，则失去心灵免疫能力（显然的，轮回者购买这一效果就不会获得心灵免疫）。<br> 传奇造魔在计算生物种类上视为构造体，因此不需要呼吸、进食和睡眠。同时将生命值转为1.5倍的结构值。同时具有基于天生或盔甲防御的【坚韧】。<br> 传奇造魔不能被只对活物有效的特效再生或复活，但传奇造魔可以在购买对应能力时将对应的效果转变为【快速维修】与【维修点数】，对应快速医疗与医疗池点数。</p><p>传奇造魔根据其来源来决定是否属于神秘侧，轮回者可以选择获得最高不超过B级的神秘属性获得，或者不获得神秘属性。</p><p>高等死灵<br> 价格：C+1200<br> 描述：它们曾经是生物，但在死去以后被神秘侧力量活化了，成为了死灵生物。该版本提供的为高等死灵，而不是通常会出现的死灵单位。<br> 效果：<br> 高等死灵免疫心灵来源的效果，也对创伤，疾病，毒素来源的效果免疫，这些免疫等级统一视为C级。但如果高等死灵具有心智或者灵魂，则失去心灵免疫能力（显然的，轮回者购买这一效果就不会获得心灵免疫）。<br> 高等死灵可以选择任意一项生理属性获得强化，该属性在检定上获得等同于内在最高支线等级*2点加值，加值类型为内在加值。</p><p>高等死灵在计算生物种类上视为不死生物，同时也是黑暗生物。<br> 高等死灵具有黑暗视觉，不需要呼吸、进食和睡眠。<br> 高等死灵不会具有生命值，而是将原本生命值转为等量的结构值处理。<br> 高等死灵不能被只对活物有效的特效再生或复活，但高等死灵可以在购买对应能力时，可以将对应的效果转变为对自身生效的快速医疗类能力。<br> 高等死灵属于神秘侧生物，具有【神秘C】，可以感受到魔力波动等神秘侧气息，这是一种新建非线性感知类能力。</p><p>狼人<br> 价格：C+1800<br> 描述：狼人通常只在月圆之夜活动，最低也得是“夜晚”，未变身时只是普通人类。<br> 效果：<br> 只有在夜晚或是满足月圆之夜的条件下，购买者才可以使用迅捷动作变身【狼人】，变身将持续一场景。<br> 变身前，购买者的种族如同普通人类一样计算，也不会获得狼人带来的好处与坏处。<br> 狼人获得该血统等级+1级的【怪力】技能。<br> 狼人在进行攻击时获得该血统等级+1级的【先制】。<br> 狼人具有等同自身传奇耐力*1点DR/银。<br> 狼人在受到具有【银】性质的攻击时，受到的伤害增加一半。</p><p>恶魔<br> 价格：C+1200/B+2400/A+4800<br> 描述：恶魔是人理之敌，是从人类恶中诞生的架空实体，近似于幻想种，却因“习性”的不同而与之分别。全世界都有恶魔的传说，它们就是邪恶的体现。<br> 效果：<br> 恶魔属于神秘侧的生物，分类为黑暗生物，具有符合其生物等级的【神秘】，以及等同生物等级的【魔性】，每个生物等级皆会获得1次【魔性】，每次必须选择不同的类型，这意味着在A级时将获得下属所有效果，但对应等级分别为C，B，A级，体现为不同恶魔对于不同领域的倾向性。<br> 恶魔具有黑暗视觉，且在某种程度上能自然的发现人类的所在，这是等同于生物等级的特异本质侦测能力，但C级恶魔不具有这一侦测能力。</p><p>当生物等级为A级时，恶魔进行的近战攻击时，可将触及范围提高到等同自身敏感范围，一旦被恶魔的攻击所击杀，则目标如同承受了S级禁止复活一样处理。<br> 特殊的是，恶魔作为种族类别不是一次性血统，而是具有多个等级的升级购买，如同正常血统一样处理。</p><p>吸血种<br> 价格：C+1200/B+2400/A+4800<br> 描述：吸食生物血液为生的幻想种的总称。“死徒”和“真祖”也被分于此类。由于全世界均有进行吸血行为的物类，而且其性质有不尽微妙的差异，所以给予其这一总称。吸血种是自然（盖亚创造）生物。<br> 大多的吸血种受不了日光，但也存在只能在日光中活动的稀有吸血种，因此主神提供的版本也进行了相应修正。<br> 效果：<br> 吸血种属于自然生物，但它们掌握、使用神秘侧力量后会具有【神秘】，因此根据生物等级具有对应等级的【神秘】，分别对应C/B/A级。<br> 吸血种生物具有【吸血 C~A】和【灵长类杀手 C~A】。<br> 吸血种生物具有黑暗视觉，不需要呼吸、进食和睡眠，但具有【吸血冲动】。<br> 主神提供的吸血种并不具有阳光弱点，但依旧会本能的厌恶阳光，以及传统意义上对于吸血鬼有效的事物，即使那些东西并非真正有效。</p><p>在A级时，吸血种生物变获得超小型集群的所有效果，同时可以藉由构成身体的（血河，蝙蝠等合适画风）部分延展进行大范围攻击，因此触及范围提升至自身的敏感范围。</p><p>【灵长目杀手】：灵长目动物的杀者。C级对于灵长目动物造成的最终伤害增加2点，在攻击检定上获得2DP内在加值；B级对于灵长目动物造成的最终伤害增加等同自身传奇力量*1点，在攻击检定上获得这个数值两倍的内在加值。<br> A级时，提供每轮一次将攻击出目增加一半的效果，同时不局限于灵长目动物，而是改为可以对所有目标生效。</p><p>【吸血冲动】：角色在12小时周期内没有至少对于非自身的人形生物造成至少1点严重伤害并饮用其血液时，就会陷入【饥饿】状态，饥饿状态下无法使用需要主动释放的招式或能力（但可以正常执行基础规则中的普通攻击等内容）。<br> 超过七十二小时后，则还会陷入【虚弱】状态，全属性减半计算。高等级吸血种可以延长真这一周期，B级的饥饿周期为一周，虚弱周期为一月。A级的饥饿周期为一月，虚弱周期为一年。</p><p>特殊的是，吸血种作为种族类别虽然也是一次性血统，但具有多个等级，每个等级相互独立购买，无法进行升级。</p><p>真祖<br> 前置：吸血种A级<br> 价格：暂不开放<br> 描述：无法对人类采取直接自卫的“星球”创造出的物种，因此可以说是自然触觉般的存在。要约束人类的话，就以人类为雏形，因此模拟人类的精神和肉体构造，真祖被制造了出来。但是真祖的诞生存在着缺陷，真祖有着吸血冲动这一问题。恐怕是作为参考的原型，其本身就存在着缺陷的缘故。<br> 效果：-</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const C=e(s,[["render",o]]);export{h as __pageData,C as default};
